import{_ as a,o as i,c as e,a2 as n}from"./chunks/framework.BflysNKA.js";const k=JSON.parse('{"title":"图像","description":"","frontmatter":{},"headers":[],"relativePath":"api/images.md","filePath":"api/images.md","lastUpdated":1778577020000}'),l={name:"api/images.md"};function p(t,s,o,r,h,d){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="图像" tabindex="-1">图像 <a class="header-anchor" href="#图像" aria-label="Permalink to &quot;图像&quot;">​</a></h1><p>图像接口沿用 OpenAI 兼容格式。先在控制台查看图像模型名称，再写进客户端或脚本。</p><p>图像任务和普通文本任务不太一样。<br> 很多时候不是地址或 Key 有问题，而是：</p><ul><li>模型类型选错了</li><li>尺寸和数量一上来就拉得太大</li><li>编辑任务没有按 <code>multipart/form-data</code> 上传文件</li></ul><p>图像任务的费用和等待时间，通常都比普通文本请求更高。第一次测试时，建议先用一张小尺寸图、一条短提示词确认链路，再继续放大尺寸或批量生成。</p><h2 id="第一次先确认什么" tabindex="-1">第一次先确认什么 <a class="header-anchor" href="#第一次先确认什么" aria-label="Permalink to &quot;第一次先确认什么&quot;">​</a></h2><p>第一次接图像接口时，先别把目标定成“生成一张非常满意的图”。<br> 更稳的顺序通常是先确认这三件事：</p><ol><li>当前模型确实是图像模型</li><li>这条请求已经能返回图片结果</li><li>你拿到的结果格式，是你后面业务真正想用的格式</li></ol><p>这样做的意义，是把“接口能不能出图”和“出图效果好不好”拆开。<br> 前者是链路问题，后者更多是模型选择、提示词和尺寸策略问题。</p><h2 id="生成图像-post" tabindex="-1">生成图像 POST <a class="header-anchor" href="#生成图像-post" aria-label="Permalink to &quot;生成图像 POST&quot;">​</a></h2><p>地址：<code>POST https://xiaolan1.cn/v1/images/generations</code></p><h3 id="常用请求参数" tabindex="-1">常用请求参数 <a class="header-anchor" href="#常用请求参数" aria-label="Permalink to &quot;常用请求参数&quot;">​</a></h3><ul><li><code>model</code>：图像模型名称</li><li><code>prompt</code>：描述词</li><li><code>size</code>：尺寸</li><li><code>n</code>：生成数量</li><li><code>response_format</code>：常见是 <code>url</code> 或 <code>b64_json</code></li></ul><p>不同图像模型支持的参数并不完全一样。<br> 第一次接入时，优先只用 <code>model</code>、<code>prompt</code>、<code>size</code>、<code>n</code> 这几个最基础的字段，把“能不能生成出来”先确认清楚；确认成功后，再去加 <code>quality</code>、<code>background</code>、参考图之类的扩展能力。</p><p>第一次如果只是想肉眼看结果，<code>response_format</code> 先用 <code>url</code> 最省事。<br> 如果你后面还要把结果继续交给脚本、后端或别的系统处理，再考虑切到 <code>b64_json</code>。</p><h3 id="示例请求" tabindex="-1">示例请求 <a class="header-anchor" href="#示例请求" aria-label="Permalink to &quot;示例请求&quot;">​</a></h3><p>先把 <code>MODEL</code> 替换成模型广场里实际可用的图像模型名：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">MODEL</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;替换成模型广场里的图像模型名&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> https://xiaolan1.cn/v1/images/generations</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;Authorization: Bearer &lt;你的 API Key&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &#39;{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">    &quot;model&quot;: &quot;&#39;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">$MODEL</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;&#39;&quot;,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">    &quot;prompt&quot;: &quot;一个白底极简科技 logo&quot;,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">    &quot;size&quot;: &quot;1024x1024&quot;,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">    &quot;n&quot;: 1,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">    &quot;response_format&quot;: &quot;url&quot;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">  }&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>如果你只是想确认接口是否可用，<code>size</code> 可以先从较小尺寸开始，<code>n</code> 也先保持 <code>1</code>。<br> 先验证返回结构，再继续放大尺寸或增加数量，这样更容易分清是接口没通，还是请求本身太重。</p><p>第一次接通时，先确认两件事：</p><ol><li>当前模型确实是图像模型，不是文本模型</li><li>返回结构里你已经拿到了可下载的 URL 或可用的 base64 结果</li></ol><p>如果第一步就只是为了确认接口通不通，提示词也尽量写得简单一点。<br> 越简单的提示词，越容易把问题锁定在接口层；等你已经证明能稳定出图，再慢慢加风格词、构图词和约束词会更清楚。</p><h2 id="调用-gptimage2" tabindex="-1">调用 gptimage2 <a class="header-anchor" href="#调用-gptimage2" aria-label="Permalink to &quot;调用 gptimage2&quot;">​</a></h2><p><code>gptimage2</code> 是图像生成模型，走 OpenAI 兼容的图像生成接口，不要填到聊天接口里。</p><p>固定地址：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line">POST https://xiaolan1.cn/v1/images/generations</span></code></pre></div><p>最小可用请求示例：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line">curl https://xiaolan1.cn/v1/images/generations \</span>
<span class="line">  -H "Content-Type: application/json" \</span>
<span class="line">  -H "Authorization: Bearer sk-你的Key" \</span>
<span class="line">  -d '{</span>
<span class="line">    "model": "gptimage2",</span>
<span class="line">    "prompt": "一只蓝色机器人在桌面上画画，干净的产品插画风格",</span>
<span class="line">    "size": "1024x1024",</span>
<span class="line">    "n": 1,</span>
<span class="line">    "response_format": "url"</span>
<span class="line">  }'</span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>返回结果一般从 <code>data[0].url</code> 里取图片地址；如果你把 <code>response_format</code> 改成 <code>b64_json</code>，就从 <code>data[0].b64_json</code> 里取 base64 图片内容。</p><p>常见报错可以这样判断：</p><ul><li><code>400</code>：优先检查 <code>model</code> 是否写成 <code>gptimage2</code>，以及 <code>size</code>、<code>n</code>、<code>response_format</code> 是否被当前模型支持。</li><li><code>404</code>：通常是地址填错了，图像生成要用 <code>/v1/images/generations</code>，不是 <code>/v1/chat/completions</code>。</li><li><code>503</code>：通常是上游模型暂时不可用或排队，先等一会再重试，也可以降低尺寸后再测试。</li></ul><p>第一次调通时建议只保留上面这几个字段。确认能稳定返回图片后，再继续加更复杂的提示词、尺寸和批量数量。</p><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ul><li>模型名直接从模型广场复制</li><li>先小图测试，再放大尺寸或批量生成</li><li>大图或长任务先看余额</li><li>图像任务通常比文本更贵，批量生成前先小额测试</li><li>如果返回的是 <code>url</code>，尽快把图片下载保存，部分链接会在一段时间后失效</li><li>如果你准备把结果继续传给别的程序处理，<code>b64_json</code> 往往比临时 URL 更稳定</li></ul><p>如果你准备做批量生成，再多看一层：<br> 同样是 <code>n=4</code>，和连续发 4 次 <code>n=1</code>，你后面做失败重试、结果保存和成本统计的方式并不完全一样。第一次联调时，先从 <code>n=1</code> 开始最稳。</p><h2 id="编辑图像-post" tabindex="-1">编辑图像 POST <a class="header-anchor" href="#编辑图像-post" aria-label="Permalink to &quot;编辑图像 POST&quot;">​</a></h2><p>地址：<code>POST https://xiaolan1.cn/v1/images/edits</code></p><p>适合局部修改、风格调整、参考图改写等场景。不同模型支持的参数会有差异，以模型广场和客户端实际能力为准。</p><p>这一类请求和普通 JSON 不一样，通常要走 <code>multipart/form-data</code>。<br> 也就是说，你传进去的不只是文字参数，还会把本地图片文件一起上传。</p><p>编辑接口第一次建议先拿一张体积小、内容简单的图片测试。<br> 如果原图本身很大、很复杂，你很难在第一次就判断到底是上传层、模型层，还是提示词本身没有描述清楚。</p><p>示例：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">MODEL</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;替换成模型广场里的图像模型名&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> https://xiaolan1.cn/v1/images/edits</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;Authorization: Bearer &lt;你的 API Key&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -F</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> model=&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">$MODEL</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -F</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> image=&quot;@input.png&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -F</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> prompt=&quot;把背景改成白色极简科技风&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="返回模型不存在" tabindex="-1">返回模型不存在 <a class="header-anchor" href="#返回模型不存在" aria-label="Permalink to &quot;返回模型不存在&quot;">​</a></h3><p>图像模型和文本模型不是一类。回模型广场复制图像模型名。</p><h3 id="生成很慢" tabindex="-1">生成很慢 <a class="header-anchor" href="#生成很慢" aria-label="Permalink to &quot;生成很慢&quot;">​</a></h3><p>图像生成通常不是秒级。先用小尺寸测试，再扩大尺寸。</p><p>如果小尺寸也明显很慢，再去看：</p><ul><li>当前模型是不是排队</li><li>当前网络是否稳定</li><li>余额是否足够支撑当前任务</li></ul><h3 id="返回内容看不到图片" tabindex="-1">返回内容看不到图片 <a class="header-anchor" href="#返回内容看不到图片" aria-label="Permalink to &quot;返回内容看不到图片&quot;">​</a></h3><p>不同模型可能返回 URL、base64 或任务结果。先打印完整响应，再按字段读取。</p><p>如果返回的是 URL，但浏览器里已经打不开，先不要急着怀疑接口。<br> 很多图像模型返回的是临时下载地址，过一段时间后自然会失效，最好在第一次拿到结果时就立即保存。</p><h3 id="编辑接口返回-400" tabindex="-1">编辑接口返回 400 <a class="header-anchor" href="#编辑接口返回-400" aria-label="Permalink to &quot;编辑接口返回 400&quot;">​</a></h3><p>优先先查这三层：</p><ul><li>你是不是用了 <code>-F image=@input.png</code> 这种文件上传写法</li><li>图片文件路径是不是实际存在</li><li>当前模型是不是支持编辑而不只是生成</li></ul><h3 id="提示词没问题-但效果很差" tabindex="-1">提示词没问题，但效果很差 <a class="header-anchor" href="#提示词没问题-但效果很差" aria-label="Permalink to &quot;提示词没问题，但效果很差&quot;">​</a></h3><p>先不要急着怀疑接口。优先先看：</p><ul><li>你是不是用了错误的模型类别</li><li>图片尺寸是不是过小</li><li>提示词是否过短、过泛</li><li>编辑任务里原图本身是否清晰</li></ul>`,48)])])}const u=a(l,[["render",p]]);export{k as __pageData,u as default};
